from collections import Counter
rows=[l.rstrip('\n').split('\t') for l in open('crh.trn') if l.strip()]

BACK=set('aıouâ')   # â treat as back for now
FRONT=set('eiöü')
VOWELS=BACK|FRONT
VOICELESS=set('pçtkqfsşh')  # after these -> voiceless suffix initial

def last_vowel(s):
    for ch in reversed(s):
        if ch.lower() in VOWELS: return ch.lower()
    return None

def is_back(s):
    lv=last_vowel(s)
    return lv in BACK if lv else True

def last_sound_voiceless(s):
    # last non-space char
    for ch in reversed(s):
        if ch==' ': continue
        return ch.lower() in VOICELESS
    return False

def low(s):   # a/e
    return 'a' if is_back(s) else 'e'
def high(s):  # ı/i/u/ü with rounding
    lv=last_vowel(s)
    back=is_back(s)
    rounded= lv in set('ouöü')
    if back:
        return 'u' if rounded else 'ı'
    else:
        return 'ü' if rounded else 'i'

def gen(lem, feat):
    pos=feat.split(';')[0]
    case=feat.split(';')[-1]
    if pos in ('N','ADJ'):
        vl=last_sound_voiceless(lem)
        back=is_back(lem)
        if case=='NOM': return lem
        if case=='ACC': return lem+'n'+high(lem)
        if case=='GEN': return lem+'n'+high(lem)+'ñ'
        if case=='DAT':
            g = ('q' if back else 'k') if vl else ('ğ' if back else 'g')
            return lem+g+low(lem)
        if case=='LOC':
            d='t' if vl else 'd'
            return lem+d+low(lem)
        if case=='ABL':
            d='t' if vl else 'd'
            return lem+d+low(lem)+'n'
    if pos=='V':
        # stem ends maq/mek -> replace
        if lem.endswith('maq'): st=lem[:-3]; back=True
        elif lem.endswith('mek'): st=lem[:-3]; back=False
        else: st=lem; back=is_back(lem)
        if feat=='V;NFIN': return lem
        if feat=='V;IMP;SG;2': return st
        if feat=='V;SG;3;PST':
            d='dı' if back else 'di'  # but data shows dı and ti/di
            return st+('dı' if back else 'di')
        if feat=='V;SG;3;PRS':
            # ends vowel? add y : else a/e
            return st+('a' if back else 'e')
    return None

ok=0; bad=[]
for lem,wf,feat in rows:
    g=gen(lem,feat)
    if g==wf: ok+=1
    else: bad.append((lem,wf,feat,g))
print("acc", ok, "/", len(rows), ok/len(rows))
bc=Counter(b[2] for b in bad)
print("errors by feat:", bc.most_common())
