            if case == "LOC":
                return lemma + "n" + P["dent"] + lo
            if case == "ABL":
                return lemma + "n" + P["dent"] + lo + "n"
        else:
            if case == "DAT":
                return lemma + P["velar"] + lo
            if case == "LOC":
                return lemma + P["dent"] + lo
            if case == "ABL":
